void CalculateOutputIndex(OpKernelContext* ctx,
                                  const Tensor* input_partition_tensor,
                                  const Tensor* input_row_partition_type_tensor,
                                  const Tensor* input_row_partition_offsets_tensor,
                                  Tensor* output_partition_tensor,
                                  Tensor* output_row_partition_offsets_tensor) {
  const auto partition_type = input_row_partition_type_tensor->flat<PartitionType>();
  const auto partition_offsets =
      input_row_partition_offsets_tensor->flat<int32>();

  const int64_t num_partitions =
      input_partition_tensor->dim_size(0);

  const int64_t num_rows = input_partition_tensor->dim_size(1);
  const int64_t num_cols = input_partition_tensor->dim_size(2);

  const auto input_partition = input_partition_tensor->flat<int32>();
  const auto input_partition_size = input_partition_tensor->NumElements();

  auto output_partition = output_partition_tensor->flat<int32>();
  auto output_partition_size = output_partition_tensor->NumElements();

  auto output_row_partition_offsets =
      output_row_partition_offsets_tensor->flat<int32>();

  OP_REQUIRES(ctx,
              output_partition_size == num_partitions * num_cols,
              errors::InvalidArgument("Partition size must be equal to "
                                      "number of partitions * number of columns"));

  OP_REQUIRES(ctx,
              output_row_partition_offsets_tensor->NumElements() ==
                  num_partitions,
              errors::InvalidArgument(
                  "Partition offset size must be equal to number of "
                  "partitions"));

  for (int64_t i = 0; i < num_partitions; i++) {
    const int32_t partition_offset =
        i > 0 ? partition_offsets(i) : 0;
    const int32_t partition_size =
        partition_offsets(i) - partition_offset;

    OP_REQUIRES(ctx,
                partition_size > 0,
                errors::InvalidArgument("Partition size must be positive"));

    OP_REQUIRES(ctx,
                partition_offset >= 0 &&
                    partition_offset <= input_partition_size,
                errors::InvalidArgument(
                    "Partition offset must be non-negative and less than "
                    "or equal to input partition size"));

    const int32_t partition_offset_in_input =
        partition_offset < input_partition_size
            ? partition_offset
            : input_partition_size;

    OP_REQUIRES(ctx,
                partition_offset_in_input >= 0 &&
                    partition_offset_in_input <= input_partition_size,
                errors::InvalidArgument(
                    "Partition offset must be non-negative and less than "
                    "or equal to input partition size"));

    const int32_t partition_size_in_input =
        std::min(partition_size, input_partition_size - partition_offset);

    OP_REQUIRES(ctx,
                partition_size_in_input > 0,
                errors::InvalidArgument("Partition size must be positive"));

    const int32_t num_rows_in_partition =
        (partition_size_in_input + num_cols - 1) / num_cols;

    OP_REQUIRES(ctx,
                num_rows_in_partition > 0,
                errors::InvalidArgument(
                    "Number of rows in partition must be positive"));

    output_row_partition_offsets(i) =
        (partition_type(i) == PartitionType::ROW_SPARSE)
            ? partition_offset_in_input
            : partition_offset;

    const int32_t partition_offset_in_output =
        output_row_partition_offsets(i) * num_cols;

    OP_REQUIRES(ctx,
                partition_offset_in_output >= 0 &&
                    partition_offset_in_output <= output_partition_size,
                errors::InvalidArgument(
                    "Partition offset in output must be non-negative and "
                    "less than or equal to output partition size"));

    const int32_t partition_size_in_output =
        std::min(partition_size_in_input, output_partition_size -
                                               partition_offset_in_output);

    OP_REQUIRES(ctx,
                partition_size_in_output > 0,
                errors::InvalidArgument("Partition size in output must be "
                                        "positive"));

    const int32_t num_rows_in_partition_output =
        (partition_size_in_output + num_cols - 1) / num_cols;

    OP_REQUIRES(ctx,
                num_rows_in_partition_output > 0,
                errors::InvalidArgument(
                    "Number of rows in partition output must be positive"));

    for (int64_t j = 0; j < num_rows_in_partition_output; j++) {
      const int32_t input_row_partition_offset =
          (j * num_cols) + partition_offset_in_input;
      const int32_t output_row_partition_offset =
          (j * num_cols) + partition_offset_in_output;

      for (int64_t k = 0; k < num_cols; k++) {
        const int32_t input_row_partition_index =
            input_row_partition_offset + k;
        const int32_t output_row_partition_index =
            output_row_partition_offset + k;

        OP_REQUIRES(ctx,
                    input_row_partition_index < input_partition_size,
                    errors::InvalidArgument(
                        "Row partition index must be less than input "
                        "partition size"));

        OP_REQUIRES(ctx,
                    output_row_partition_index < output_partition_size,
                    errors::InvalidArgument(
                        "Row partition index must be less than output "
                        "partition size"));

        output_partition(output_row_partition_index) =
            input_partition(input_row_partition_index);
      }
    }
  }
}

