#include "cache.h"
#include "config.h"
#include "parse-options.h"
#include "submodule.h"

static void fsck_gitmodules_fn(const char *path, struct object_id *oid,
			       int flag, void *cb_data)
{
	const char *name;
	const char *value;
	struct strbuf buf = STRBUF_INIT;
	struct strbuf pathbuf = STRBUF_INIT;
	int len;
	int ret = 0;

	if (flag & GITMODULES_RECURSE)
		return;

	if (S_ISGITLINK(flag))
		return;

	name = strrchr(path, '/');
	if (!name)
		return;

	name++;
	if (name[0] == '.')
		return;

	value = parse_config_key(path, "submodule", name, &buf);
	if (!value)
		return;

	strbuf_addf(&pathbuf, "%s/", path);
	len = strlen(pathbuf.buf);

	while (value) {
		if (check_submodule_name(value, len)) {
			strbuf_setlen(&buf, 0);
			strbuf_addf(&buf, "submodule.%s.path", name);
			report(path, buf.buf, "invalid submodule name", value);
			ret = 1;
			break;
		}
		value = parse_config_key(value, "submodule", name, &buf);
	}

	strbuf_release(&buf);
	strbuf_release(&pathbuf);

	return ret;
}

