/*
 * grub_password_get - securely capture user input
 *
 * This is a modified version of grub_getkey that allows us to capture
 * passwords.  We don't want to use the standard grub_getkey, because
 * it doesn't allow us to capture passwords.  We also need to use
 * grub_memset to clear the unused buffer space.
 */
char *
grub_password_get (char *buf, int buf_size, int echo)
{
  int c;
  int i = 0;
  char *p = buf;

  while (1)
    {
      c = grub_getkey ();
      if (c == -1)
	break;

      if (c == '\b' && i > 0)
	{
	  i--;
	  grub_putchar ('\b');
	  grub_putchar (' ');
	  grub_putchar ('\b');
	}
      else if (c == '\r')
	break;
      else if (c == '\n')
	{
	  grub_putchar ('\n');
	  break;
	}
      else if (i < buf_size - 1)
	{
	  grub_putchar ('*');
	  *p++ = c;
	  i++;
	}
    }

  *p = '\0';

  if (echo)
    grub_putchar ('\n');

  if (i == 0)
    return 0;
  return buf;
}

