void FrameFactory::RebuildAggregateFrames(const ID3v2Frame& frame, ID3v2Tag* tag)
{
    if (frame.GetFrameID() == ID3v2Frame::FID_TDRC)
    {
        const ID3v2Frame::TextFrame& textFrame = static_cast<const ID3v2Frame::TextFrame&>(frame);
        if (!textFrame.GetText().empty())
        {
            if (tag->GetYear() == 0)
                tag->SetYear(textFrame.GetText().substr(0, 4).ToInt());
            if (tag->GetDate().empty())
                tag->SetDate(textFrame.GetText().substr(4, 4).ToInt());
        }
    }
    else if (frame.GetFrameID() == ID3v2Frame::FID_TDAT)
    {
        const ID3v2Frame::TextFrame& textFrame = static_cast<const ID3v2Frame::TextFrame&>(frame);
        if (!textFrame.GetText().empty())
        {
            if (tag->GetDate().empty())
                tag->SetDate(textFrame.GetText().ToInt());
        }
    }
    else if (frame.GetFrameID() == ID3v2Frame::FID_TIME)
    {
        const ID3v2Frame::TextFrame& textFrame = static_cast<const ID3v2Frame::TextFrame&>(frame);
        if (!textFrame.GetText().empty())
        {
            if (tag->GetTime().empty())
                tag->SetTime(textFrame.GetText().ToInt());
        }
    }
}

