//
//
//	Read and debug PixMap header fields using the `dbuf_getu16be` and `dbuf_getu32be` functions from a specified position in a buffer.
//
//	Inputs:
//			dbuf:					The buffer containing the PixMap header.
//			pos:						The offset into the buffer at which the PixMap header starts.
//
//	Outputs:
//			*width:					The width of the PixMap.
//			*height:					The height of the PixMap.
//			*bit_depth:				The number of bits per pixel in the PixMap.
//			*channels:				The number of color channels in the PixMap.
//
//	Returns:
//			An error code.
//
//

int read_pixmap_header(dbuf *dbuf, uint32_t pos, uint16_t *width, uint16_t *height, uint16_t *bit_depth, uint16_t *channels)
{
	int err;
	uint32_t size;

	err = dbuf_seek(dbuf, pos, SEEK_SET);
	if (err)
		return err;

	size = dbuf_getu32be(dbuf);
	if (size != 12)
		return -1;

	*width = dbuf_getu16be(dbuf);
	*height = dbuf_getu16be(dbuf);
	*bit_depth = dbuf_getu16be(dbuf);
	*channels = dbuf_getu16be(dbuf);

	return 0;
}

