void slc_bump(struct net_device *dev, struct can_frame *cf)
{
	struct can_skb_priv *skb_priv;
	struct can_frame *cf2;
	struct can_frame *cf_end;
	int i;

	skb_priv = netdev_priv(dev);
	cf2 = skb_priv->head;
	cf_end = cf2 + skb_priv->skb->len;
	for (; cf2 < cf_end; cf2++) {
		if (cf2->can_id == cf->can_id && cf2->can_dlc == cf->can_dlc) {
			for (i = 0; i < cf->can_dlc; i++)
				cf2->data[i] = cf->data[i];
			return;
		}
	}

	if (cf2 >= cf_end)
		return;

	memcpy(cf2, cf, sizeof(struct can_frame));
}

