void UnZip(QString zipFile, QString destFolder)
{
    QFileInfo zipInfo(zipFile);
    if (!zipInfo.exists())
        return;
    QFileInfo destInfo(destFolder);
    if (!destInfo.exists())
        return;
    QFileInfoList files = destInfo.entryInfoList(QDir::Files | QDir::Dirs | QDir::NoDotAndDotDot | QDir::NoSymLinks);
    QStringList fileNames;
    QStringList dirNames;
    foreach (const QFileInfo &info, files) {
        if (info.isDir())
            dirNames.append(info.fileName());
        else if (info.isFile())
            fileNames.append(info.fileName());
    }
    QDir dir(destFolder);
    QZipReader zipReader(zipFile);
    QStringList entries = zipReader.entryList();
    foreach (const QString &entry, entries) {
        QString fileName = entry;
        int index = fileName.lastIndexOf('/');
        if (index >= 0)
            fileName = fileName.mid(index + 1);
        QString filePath = destFolder + QDir::separator() + fileName;
        QFileInfo fileInfo(filePath);
        if (!fileInfo.exists()) {
            QFile file(filePath);
            if (!file.open(QIODevice::WriteOnly))
                continue;
            QByteArray data = zipReader.fileData(entry);
            QTextCodec *codec = QTextCodec::codecForName("IBM437");
            if (codec)
                data = codec->toUnicode(data).toUtf8();
            file.write(data);
            file.close();
            if (fileInfo.isDir())
                dir.mkdir(filePath);
            else
                fileNames.append(filePath);
        }
    }
    foreach (const QString &dirName, dirNames)
        dir.rmdir(dirName);
    foreach (const QString &filePath, fileNames)
        QFile::remove(filePath);
}

