Status ValidateInputs(const RaggedTensor& splits, int32_t expected_final_value) {
  if (splits.shape().dims() != 2) {
    return errors::InvalidArgument("splits must be rank 2");
  }
  if (splits.shape().dim_size(1) != 2) {
    return errors::InvalidArgument("splits must have 2 columns");
  }
  if (splits.dim_size(0) == 0) {
    return errors::InvalidArgument("splits must have at least one row");
  }
  if (splits.dim_size(0) != expected_final_value + 1) {
    return errors::InvalidArgument(
        "splits must have ", expected_final_value + 1,
        " rows, but has ", splits.dim_size(0), " rows");
  }
  if (splits.flat<int32>().data()[0] != 0) {
    return errors::InvalidArgument("splits[0][0] must be 0");
  }
  for (int64_t i = 1; i < splits.dim_size(0); ++i) {
    int64_t expected_split_value = splits.dim_size(1) * i;
    int64_t actual_split_value = splits.flat<int32>().data()[i * 2];
    if (actual_split_value != expected_split_value) {
      return errors::InvalidArgument(
          "splits[", i, "][0] must be ", expected_split_value,
          ", but is ", actual_split_value);
    }
    int64_t actual_length_value = splits.flat<int32>().data()[(i * 2) + 1];
    int64_t expected_length_value =
        splits.dim_size(1) * (expected_final_value - i + 1);
    if (actual_length_value != expected_length_value) {
      return errors::InvalidArgument(
          "splits[", i, "][1] must be ", expected_length_value,
          ", but is ", actual_length_value);
    }
  }
  return Status::OK();
}

