static int on_header_field(struct http_parser *parser, const char *at,
                           size_t length)
{
    if (parser->state == s_header_value_almost_done) {
        STRICT_CHECK(length);
        parser->state = s_header_field;
    }

    if (parser->header_field) {
        size_t old_len = parser->header_field_mark ?
            (size_t)(parser->header_field_mark - parser->header_field) : 0;
        void *header_field =
            realloc(parser->header_field, old_len + length + 1);

        if (header_field == NULL) {
            return 1;
        }

        parser->header_field = header_field;
        parser->header_field_mark =
            (char *)parser->header_field + old_len;
        memcpy((char *)parser->header_field + old_len, at, length);
        parser->header_field_mark[length] = 0;
    } else {
        parser->header_field = (char *)at;
        parser->header_field_mark = (char *)at;
    }

    parser->state = s_header_value;

    return 0;
}

