static int on_headers_complete(struct http_parser *parser)
{
    int rc = 0;
    if (parser->header_field) {
        if (parser->header_value) {
            on_header(parser, parser->header_field, parser->header_value);
        } else {
            on_header(parser, parser->header_field, NULL);
        }
        parser->header_field = NULL;
        parser->header_value = NULL;
    }

    switch (parser->state) {
    case s_chunk_size_start:
        if (parser->flags & F_TRAILING) {
            /* chunked encoding */
            parser->state = (parser->flags & F_CONTENT_LENGTH) ?
                s_chunk_data_almost_done :
                s_chunk_data_done;
            break;
        }

        if (parser->content_length == 0) {
            /* content-length header given, no body */
            parser->state = s_message_done;
            break;
        }

        /* fall through */
    case s_body_identity:
        parser->state = s_body_identity_eof;
        break;

    case s_body_identity_eof:
        /* Using the `content-length` or `transfer-encoding: chunked`
         * concepts is mutually exclusive.  `content-length` implies
         * that there is a content length indicated in the headers.
         * `transfer-encoding` implies that the chunked encoding will
         * be used to transmit the content.  Error if both are
         * present together in a request, or if `content-length` is
         * present in a response.
         */
        if (parser->flags & F_CONTENT_LENGTH) {
            if (!http_message_needs_eof(parser)) {
                /* CONNECT is the only method using transfer-encoding
                 * and the CONNECT method as specified RFC 7231 section
                 * 4.3.6 requires that a content-length header field is
                 * not sent in a CONNECT request.
                 */
                if (parser->method != HTTP_CONNECT) {
                    parser->http_errno = HPE_UNEXPECTED_CONTENT_LENGTH;
                    return 1;
                }
            }
        } else {
            if (parser->content_length != 0) {
                /* Unexpected content-length */
                parser->http_errno = HPE_UNEXPECTED_CONTENT_LENGTH;
                return 1;
            }

            if (parser->flags & F_CHUNKED) {
                /* Unexpected transfer-encoding */
                parser->http_errno = HPE_UNEXPECTED_TRANSFER_ENCODING;
                return 1;
            }
        }

        parser->state = (parser->flags & F_SKIPBODY) ?
            s_message_done : s_body_identity;
        break;

    case s_body_identity_eof_already:
        break;

    default:
        assert(0 && "on_headers_complete: unexpected state");
        break;
    }

    /* Set this here so that on_headers_complete() call chaining works
     * as expected when switching on_headers_complete() calls to
     * on_header_value() calls.
     */
    parser->upgrade = parser->flags & F_UPGRADE;

    if (parser->flags & F_SKIPBODY) {
        /* skip body */
        parser->state = s_message_done;
    }

    if (parser->cb) {
        rc = parser->cb(parser, HTTP_CB_HEADERS_COMPLETE);
        if (rc != 0) {
            return rc;
        }
    }

    parser->nread = 0;

    return 0;
}

