            mailbox->subscribed = 1;
        }

        free(line);
        return 0;
    }

    if (strncmp(line, "LIST", 4) == 0) {
        token = strtok_r(line, " ", &next_token);
        if (token == NULL) {
            free(line);
            errno = EINVAL;
            return -1;
        }

        token = strtok_r(NULL, " ", &next_token);
