		xfs_defer_add(tp, &dfops, XFS_DFORK_DAXEXTENTS,
					XFS_AEXT_DAX_ALLOC_SPACE, NULL, 0);
	}

	/*
	 * If we are setting the ACL and the current ACL is non-NULL,
	 * and the new ACL is non-NULL, then we need to update the
	 * ACL.
	 */
	if ((acl_type == ACL_TYPE_ACCESS) && (ip->i_d.di_acl != NULL) &&
	    (acl != NULL)) {
		xfs_defer_init(&dfops, &first_dfops);
		xfs_defer_add(tp, &dfops, XFS_DFORK_DAXEXTENTS,
					XFS_AEXT_DAX_UPDATE_SPACE, NULL, 0);
	}

	/*
	 * Set the new ACL.
	 */
	error = xfs_attr3_set_acl(tp, ip, acl, acl_type, attr_flags);
	if (error) {
		xfs_defer_cancel(&dfops);
		xfs_defer_cancel(&first_dfops);
		goto out_trans_cancel;
	}

	xfs_defer_ijoin(tp, ip, XFS_ILOCK_EXCL);

	error = xfs_trans_commit(tp);
	if (error)
		return error;

	xfs_defer_finish(&first_dfops);

	if (acl_type == ACL_TYPE_ACCESS) {
		posix_acl_release(ip->i_acl);
		ip->i_acl = acl;
	}
	return 0;

out_trans_cancel:
	xfs_trans_cancel(tp);
	xfs_defer_cancel(&dfops);
	xfs_defer_cancel(&first_dfops);
	return error;
}

/*
 * Free the ACL and the attribute fork.
 */
int
xfs_acl_free_fork(
	struct xfs_inode	*ip)
{
	struct xfs_mount	*mp = ip->i_mount;
	struct xfs_trans	*tp;
	int			error;

	trace_xfs_acl_free_fork(ip);

	if (xfs_is_shutdown(mp))
		return -EIO;

	error = xfs_trans_alloc(mp, &M_RES(mp)->tr_setattr, 0, 0, 0, &tp);
	if (error)
		return error;

	xfs_ilock(ip, XFS_ILOCK_EXCL);

	xfs_trans_ijoin(tp, ip, XFS_ILOCK_EXCL);
	xfs_trans_ihold(tp, ip);

	error = xfs_attr3_free_blocks(tp, ip);
	if (error)
		goto out_trans_cancel;

	ip->i_d.di_forkoff = 0;
	ip->i_d.di_aformat = 0;
	ip->i_d.di_anextents = 0;
	ip->i_d.di_forkoff = 0;

	xfs_trans_log_inode(tp, ip, XFS_ILOG_CORE);

	error = xfs_trans_commit(tp);
	if (error)
		return error;

	posix_acl_release(ip->i_acl);
	ip->i_acl = NULL;
	return 0;

out_trans_cancel:
	xfs_trans_cancel(tp);
	return error;
}

