	struct posix_acl	*acl,
	gid_t			gid)
{
	struct posix_acl_entry	*pae;
	int			i;

	if (!acl)
		return 0;

	for (i = 0; i < acl->a_count; i++) {
		pae = &acl->a_entries[i];
		if (pae->e_tag == ACL_USER)
			return 1;
		if (pae->e_tag == ACL_GROUP && pae->e_id == gid)
