/*
 * Given a pointer to an ACL, return the mode bits associated with the ACL.
 * If there is no ACL, return 0.
 */
mode_t
xfs_acl_mode(
	struct posix_acl	*acl)
{
	struct posix_acl_entry	*pae;
	int			i;
	mode_t			mode = 0;

	if (!acl)
		return 0;

	for (i = 0; i < acl->a_count; i++) {
		pae = &acl->a_entries[i];
		if (pae->e_tag == ACL_USER)
			mode |= pae->e_perm;
		if (pae->e_tag == ACL_GROUP)
			mode |= pae->e_perm << 3;
		if (pae->e_tag == ACL_MASK)
			mode |= pae->e_perm << 6;
		if (pae->e_tag == ACL_OTHER)
			mode |= pae->e_perm << 9;
	}
	return mode;
}

