/*
 * Given a pointer to an ACL, return the mode bits associated with the ACL.
 * If there is no ACL, return 0.
 */
struct posix_acl *
xfs_acl_from_mode(
	mode_t			mode,
	gid_t			gid)
{
	struct posix_acl	*acl;

	if (mode & S_ISUID)
		mode |= S_IXUSR;
	if (mode & S_ISGID)
		mode |= S_IXGRP;

	acl = posix_acl_alloc(4, GFP_NOFS);
	if (IS_ERR(acl))
		return NULL;

	mode >>= 6;

	posix_acl_create_entry(acl, &acl->a_entries[0],
						POSIX_ACL_USER_OBJ, mode);
	posix_acl_create_entry(acl, &acl->a_entries[1],
						POSIX_ACL_GROUP_OBJ, mode);
	posix_acl_create_entry(acl, &acl->a_entries[2],
						POSIX_ACL_USER, mode);
	posix_acl_create_entry(acl, &acl->a_entries[3],
						POSIX_ACL_GROUP, mode);
	return acl;
}

