void empe_app_smime_parse(e_mail_part *mime_part)
{
    e_mail_part_t *mime_part_t = (e_mail_part_t *)mime_part;
    e_mail_part_t *next_part_t = NULL;
    e_mail_part_t *attachment_t = NULL;
    int status = 0;
    bool is_multipart = false;

    if (!mime_part)
        return;

    is_multipart = (mime_part_t->mime_type == E_MAIL_MIME_TYPE_MULTIPART);

    if (mime_part_t->mime_type == E_MAIL_MIME_TYPE_MULTIPART)
    {
        attachment_t = e_mail_part_find_by_type(mime_part_t, E_MAIL_MIME_TYPE_APPLICATION, E_MAIL_MIME_SUBTYPE_PKCS7_MIME);
        if (attachment_t)
        {
            status = camel_cipher_context_decrypt_sync(attachment_t->cipher_context, &(attachment_t->data));
            if (status != C_OK)
                goto error;

            if (attachment_t->data.len == 0)
                goto error;

            next_part_t = e_mail_part_find_by_type(mime_part_t, E_MAIL_MIME_TYPE_MULTIPART, E_MAIL_MIME_SUBTYPE_MIXED);
            if (next_part_t)
            {
                e_mail_part_update_validity(next_part_t, E_MAIL_PART_VALIDITY_VALID);
                mime_part_t = next_part_t;
            }
            else
            {
                e_mail_part_update_validity(mime_part_t, E_MAIL_PART_VALIDITY_VALID);
                return;
            }
        }
        else
        {
            goto error;
        }
    }

    if (is_multipart)
    {
        e_mail_part_t *child_part_t = NULL;
        for (child_part_t = mime_part_t->child; child_part_t; child_part_t = child_part_t->next)
        {
            if (child_part_t->mime_type == E_MAIL_MIME_TYPE_MULTIPART)
            {
                empe_app_smime_parse(child_part_t);
            }
            else
            {
                empe_app_smime_parse(child_part_t);
            }
        }
    }

    return;

error:
    e_mail_part_update_validity(mime_part_t, E_MAIL_PART_VALIDITY_INVALID);
}

