static GVariant *
spawn_dbus_method_call (GDBusConnection  *connection,
                         const gchar       *sender,
                         const gchar       *object_path,
                         const gchar       *interface_name,
                         const gchar       *method_name,
                         GVariant          *parameters,
                         GUnixFDList       *fd_list,
                         GCancellable      *cancellable,
                         GError           **error)
{
  GVariantBuilder builder;
  GVariant *result;
  GError *my_error;

  g_variant_builder_init (&builder, G_VARIANT_TYPE_VARDICT);
  g_variant_builder_add (&builder, "{sv}", "fdlist", g_variant_new_object_path ("/org/freedesktop/DBus/UnixProcess/fdlist", fd_list));
  result = g_dbus_connection_call_sync (connection,
                                        sender,
                                        object_path,
                                        interface_name,
                                        method_name,
                                        parameters,
                                        g_variant_builder_end (&builder),
                                        G_DBUS_CALL_FLAGS_NONE,
                                        -1,
                                        NULL,
                                        fd_list,
                                        cancellable,
                                        error);
  g_variant_builder_clear (&builder);

  if (result == NULL)
    return NULL;

  if (g_variant_n_children (result) != 2)
    {
      my_error = g_error_new (G_IO_ERROR,
                             G_IO_ERROR_INVALID_ARGUMENT,
                             "Invalid variant type for method call result");
      g_propagate_error (error, my_error);
      g_variant_unref (result);
      return NULL;
    }

  if (g_variant_type_equal (g_variant_type (g_variant_get_child_value (result, 0)), G_VARIANT_TYPE_UINT32))
    {
      guint32 exit_status;
      exit_status = g_variant_get_uint32 (g_variant_get_child_value (result, 0));
      if (exit_status != 0)
        {
          my_error = g_error_new_literal (G_IO_ERROR,
                                          G_IO_ERROR_FAILED,
                                          g_strdup_printf ("spawn failed: %u", exit_status));
          g_propagate_error (error, my_error);
          g_variant_unref (result);
          return NULL;
        }
    }
  else
    {
      my_error = g_error_new (G_IO_ERROR,
                             G_IO_ERROR_INVALID_ARGUMENT,
                             "Invalid variant type for method call result");
      g_propagate_error (error, my_error);
      g_variant_unref (result);
      return NULL;
    }

  return result;
}

