static int
iasecc_select_file(sc_session *sc_sess, int fcid, unsigned char *fid,
				   size_t fid_len, int ftyp)
{
	int rc;
	unsigned char buf[258];
	size_t buf_len;
	int ftyp_len;
	sc_log_err_t *err;

	if (fid_len > 256) {
		err = sc_log_new();
		if (!err)
			return -ENOMEM;
		sc_log_set_err(err, SC_LOG_ERR,
				"File ID too long, max 256 bytes");
		sc_log_report(sc_sess->sc_log, err);
		sc_log_free(err);
		return -EINVAL;
	}

	ftyp_len = (ftyp == 0) ? 0 : 1;

	buf[0] = 0x00;
	buf[1] = ftyp_len;
	buf[2] = ftyp;
	memcpy(buf + 3, fid, fid_len);
	buf_len = 3 + fid_len;

	rc = sc_transceive(sc_sess, buf, buf_len, buf, sizeof(buf),
					   NULL, 0, 0, 0, 0, 0, NULL, NULL, 0);
	if (rc != 0) {
		err = sc_log_new();
		if (!err)
			return -ENOMEM;
		sc_log_set_err(err, SC_LOG_ERR, "Error selecting file %d",
					   fcid);
		sc_log_report(sc_sess->sc_log, err);
		sc_log_free(err);
		return rc;
	}

	if (buf[0] != 0x90 || buf[1] != 0x00) {
		err = sc_log_new();
		if (!err)
			return -ENOMEM;
		sc_log_set_err(err, SC_LOG_ERR, "Error selecting file %d",
					   fcid);
		sc_log_report(sc_sess->sc_log, err);
		sc_log_free(err);
		return -EINVAL;
	}

	return 0;
}

