static void dwc3_gadget_giveback(struct dwc3_ep *dep, struct dwc3_request *req)
{
	struct usb_request	*ureq = &req->request;
	unsigned long		flags;
	int			status = 0;

	spin_lock_irqsave(&dep->endpoint.lock, flags);
	list_del(&req->list);
	spin_unlock_irqrestore(&dep->endpoint.lock, flags);

	if (req->request.status == -EOPNOTSUPP) {
		dev_dbg(dep->dwc->dev, "%s: %s stall\n", dep->name,
				req->request.ep->name);
		dwc3_gadget_ep_set_halt(dep, 1);
		status = -EPERM;
