			status = usb_ep_queue(dep->endpoint.ep,
					&req_queued->request, GFP_ATOMIC);
		if (status)
			dwc3_gadget_giveback(dep, req_queued);
	}
	spin_unlock_irqrestore(&dep->endpoint.lock, flags);
