int fuse_do_readpage(struct fuse_file_info *fi, struct page *pg, int create)
{
	struct inode *inode = pg->mapping->host;
	struct fuse_conn *fc = get_fuse_conn_for_inode(inode);
	struct fuse_req *req;
	struct fuse_read_in *ri;
	int err;

	if (create) {
		fuse_lock_inode(inode);
		if (is_bad_inode(inode)) {
			fuse_unlock_inode(inode);
			return -EIO;
		}
	}

	req = fuse_get_req_for_background(fc);
	if (IS_ERR(req)) {
		err = PTR_ERR(req);
		goto out_unlock;
	}

	ri = &req->misc.read_in;
	memset(ri, 0, sizeof(struct fuse_read_in));
	ri->fh = get_node_id(inode);
	ri->offset = page_offset(pg) << PAGE_CACHE_SHIFT;
	ri->size = PAGE_CACHE_SIZE;
	ri->flags = FUSE_READ_UNBUFFERED;

	err = fuse_read_fill(req, ri, pg, 0);
	if (err) {
		fuse_put_request(fc, req);
		goto out_unlock;
	}
	req->background = 1;
	fuse_request_send(fc, req);
	fuse_put_request(fc, req);
	if (create) {
		fuse_unlock_inode(inode);
		fuse_invalidate_atime(inode);
	}
	return 0;

out_unlock:
	if (create)
		fuse_unlock_inode(inode);
	return err;
}

int fuse_readpage(struct file *file, struct page *page)
{
	return fuse_do_readpage(file->private_data, page, 0);
}

