{
    struct fontx *fontx;
    struct fontx_info *info;
    int retval = 0;
    int copy_size = 0;

    fontx = (struct fontx *)get_fd_priv(fd);
    if (!fontx)
        return -EINVAL;

    switch (cmd) {
    case GIO_FONTX:
        info = (struct fontx_info *)arg;
        copy_size = sizeof(struct fontx_info);
        if (copy_from_user(&info->info, &fontx->info, copy_size))
            return -EFAULT;
        break;

    case PIO_FONTX:
        info = (struct fontx_info *)arg;
        copy_size = sizeof(struct fontx_info);
        if (copy_from_user(&fontx->info, &info->info, copy_size))
            return -EFAULT;
        break;

    default:
        return -EINVAL;
    }

    return retval;
}

