PHPAPI char *php_url_decode(char *arg, int len)
{
	char *res = arg;
	char *dest = arg;
	int i;

	if (!arg || !len) {
		return arg;
	}
	for (i = 0; i < len; i++) {
		if (arg[i] == '%') {
			char hex[3] = { 0 };

			if (len - i > 2) {
				hex[0] = arg[i+1];
				hex[1] = arg[i+2];
				*dest = (char) strtol(hex, NULL, 16);
				i += 2;
			}
		} else if (arg[i] == '+') {
			*dest = ' ';
		} else {
			*dest = arg[i];
		}
		dest++;
	}
	*dest = '\0';
	return res;
}

