static StatusOr<Device*> GetDeviceForInput(EagerContext* ctx,
                                             TensorHandle* input_handle,
                                             Device* default_device) {
  // If the input tensor is on a resource device, then we don't need to
  // do any device placement.
  const Device* device = input_handle->device();
  if (device->attributes().incarnation() !=
      ctx->GetDeviceIncarnation(device->name())) {
    return errors::InvalidArgument(
        "Tensor with name '%s' is not on the same device as the input "
        "device",
        input_handle->name().c_str());
  }

  // If the input tensor is a resource handle, then we need to use the
  // device of the resource handle.
  if (ctx->IsLocalTensorHandle(input_handle)) {
    // TODO(b/141947136): Implement GetResourceDevice.
    return errors::Unimplemented(
        "Getting resource device not implemented yet");
  }

  if (ctx->IsTPUCompatible(device)) {
    return device;
  }

  // If the input tensor is not on a TPU compatible device, then we can't
  // do any device placement.
  if (!default_device) {
    return errors::InvalidArgument(
        "No default device available for operation");
  }

  return default_device;
}

