            mac_alg_id_len = BIO_get_mem_data(in, (char **)&mac_alg_id);

            if (mac_alg_id_len < 0) {
                PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
                goto err;
            }

            if (mac_alg_id_len == 0) {
                PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
                goto err;
            }

            ctx->mac_alg_id = (size_t)mac_alg_id_len;

            ctx->mac_alg_id_len = mac_alg_id_len;

            ctx->mac_alg_id_set = 1;
        }
    }

    if (ctx->content_type_len_len == 0) {
        if (ctx->content_type_len_set == 0) {
            content_type_len_len = BIO_get_mem_data(in, (char **)&content_type_len);

            if (content_type_len_len < 0) {
                PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
                goto err;
            }

            if (content_type_len_len == 0) {
                PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
                goto err;
            }

            ctx->content_type_len = (size_t)content_type_len_len;

            ctx->content_type_len_len = content_type_len_len;

            ctx->content_type_len_set = 1;
        }
    }

    /*
     * We have to read all the data we can.
     * We can't do it in one go because we don't know the length of the
     * data.
     */
    if (ctx->content_len_len == 0) {
        content_len_len = BIO_get_mem_data(in, (char **)&content_len);

        if (content_len_len < 0) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
            goto err;
        }

        if (content_len_len == 0) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
            goto err;
        }

        ctx->content_len = (size_t)content_len_len;

        ctx->content_len_len = content_len_len;

        ctx->content_len_set = 1;
    }

    if (ctx->content_len_set == 0) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
        goto err;
    }

    content = OPENSSL_malloc(ctx->content_len);

    if (content == NULL) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, ERR_R_MALLOC_FAILURE);
        goto err;
    }

    if (!BIO_read(in, content, ctx->content_len)) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_BIO_ERROR);
        goto err;
    }

    if (ctx->mac_key_len_len == 0) {
        mac_key_len_len = BIO_get_mem_data(in, (char **)&mac_key_len);

        if (mac_key_len_len < 0) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
            goto err;
        }

        if (mac_key_len_len == 0) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
            goto err;
        }

        ctx->mac_key_len = (size_t)mac_key_len_len;

        ctx->mac_key_len_len = mac_key_len_len;

        ctx->mac_key_len_set = 1;
    }

    if (ctx->mac_key_len_set == 0) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
        goto err;
    }

    if (ctx->mac_key == NULL) {
        mac_key = OPENSSL_malloc(ctx->mac_key_len);

        if (mac_key == NULL) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, ERR_R_MALLOC_FAILURE);
            goto err;
        }

        if (!BIO_read(in, mac_key, ctx->mac_key_len)) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_BIO_ERROR);
            goto err;
        }

        ctx->mac_key = mac_key;
    }

    if (ctx->mac_len_len == 0) {
        mac_len_len = BIO_get_mem_data(in, (char **)&mac_len);

        if (mac_len_len < 0) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
            goto err;
        }

        if (mac_len_len == 0) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
            goto err;
        }

        ctx->mac_len = (size_t)mac_len_len;

        ctx->mac_len_len = mac_len_len;

        ctx->mac_len_set = 1;
    }

    if (ctx->mac_len_set == 0) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
        goto err;
    }

    mac = OPENSSL_malloc(ctx->mac_len);

    if (mac == NULL) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, ERR_R_MALLOC_FAILURE);
        goto err;
    }

    if (!BIO_read(in, mac, ctx->mac_len)) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_BIO_ERROR);
        goto err;
    }

    if (ctx->content_type_len_len == 0) {
        content_type_len_len = BIO_get_mem_data(in, (char **)&content_type_len);

        if (content_type_len_len < 0) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
            goto err;
        }

        if (content_type_len_len == 0) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
            goto err;
        }

        ctx->content_type_len = (size_t)content_type_len_len;

        ctx->content_type_len_len = content_type_len_len;

        ctx->content_type_len_set = 1;
    }

    if (ctx->content_type_len_set == 0) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
        goto err;
    }

    content_type = OPENSSL_malloc(ctx->content_type_len);

    if (content_type == NULL) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, ERR_R_MALLOC_FAILURE);
        goto err;
    }

    if (!BIO_read(in, content_type, ctx->content_type_len)) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_BIO_ERROR);
        goto err;
    }

    if (ctx->content_type_oid == NULL) {
        ctx->content_type_oid = OBJ_txt2obj(content_type, 0);

        if (ctx->content_type_oid == NULL) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_CONTENT_TYPE);
            goto err;
        }
    }

    /*
     * Check whether the content type is the same as the one we expected.
     */
    if (OBJ_cmp(ctx->content_type_oid, ctx->expected_content_type_oid)) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_CONTENT_TYPE);
        goto err;
    }

    if (ctx->mac_alg_id_len == 0) {
        mac_alg_id_len = BIO_get_mem_data(in, (char **)&mac_alg_id);

        if (mac_alg_id_len < 0) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
            goto err;
        }

        if (mac_alg_id_len == 0) {
            PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
            goto err;
        }

        ctx->mac_alg_id = (size_t)mac_alg_id_len;

        ctx->mac_alg_id_len = mac_alg_id_len;

        ctx->mac_alg_id_set = 1;
    }

    if (ctx->mac_alg_id_set == 0) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_INVALID_LENGTH);
        goto err;
    }

    if (ctx->mac_alg_id != NID_hmac) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_UNSUPPORTED_MAC_TYPE);
        goto err;
    }

    if (ctx->mac_key_len != MMA_KEY_LEN) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_UNSUPPORTED_MAC_KEY_LENGTH);
        goto err;
    }

    if (!BIO_write(out, content, ctx->content_len)) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_BIO_ERROR);
        goto err;
    }

    if (ctx->mac_len != SHA_DIGEST_LENGTH) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_UNSUPPORTED_MAC_LENGTH);
        goto err;
    }

    if (ctx->mac_alg_id != NID_hmac) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_UNSUPPORTED_MAC_TYPE);
        goto err;
    }

    p = mac;

    if (HMAC(EVP_sha1(), mac_key, ctx->mac_key_len, content, ctx->content_len, mac, NULL) == NULL) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, ERR_R_MALLOC_FAILURE);
        goto err;
    }

    if (memcmp(p, mac, ctx->mac_len) != 0) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE_DO_FINAL, PKCS7_R_MAC_VERIFICATION_FAILURE);
        goto err;
    }

    rv = 1;

err:

    if (content != NULL) {
        OPENSSL_free(content);
    }

    if (mac != NULL) {
        OPENSSL_free(mac);
    }

    if (content_type != NULL) {
        OPENSSL_free(content_type);
    }

    if (mac_key != NULL) {
        OPENSSL_free(mac_key);
    }

    return rv;
}

int
PKCS7_dataDecode(BIO *in, BIO *out, const EVP_MD *md, OBJ_ID *content_type,
    OBJ_ID *expected_content_type, int flags)
{
    PKCS7_DATA_CTX ctx;
    int rv = 0;

    if (PKCS7_dataDecode_do_init(&ctx, in, out) <= 0) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE, PKCS7_R_PKCS7_LIB);
        return 0;
    }

    if (expected_content_type != NULL) {
        ctx.expected_content_type_oid = expected_content_type;
    }

    if (PKCS7_dataDecode_do_final(&ctx, in, out) <= 0) {
        PKCS7err(PKCS7_F_PKCS7_DATA_DECODE, PKCS7_R_PKCS7_LIB);
        goto err;
    }

    rv = 1;

err:

    return rv;
}
